import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"散王剑阵符","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/5.S级/散王剑阵符.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/5.S级/散王剑阵符.md"}'),p={name:"4.资源分区/7.物品与装备/9.消耗品/5.S级/散王剑阵符.md"};function d(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"散王剑阵符",tabindex:"-1"},[s("散王剑阵符 "),e("a",{class:"header-anchor",href:"#散王剑阵符","aria-label":'Permalink to "散王剑阵符"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),o('<h1 id="散王剑阵符-1" tabindex="-1">散王剑阵符 <a class="header-anchor" href="#散王剑阵符-1" aria-label="Permalink to &quot;散王剑阵符&quot;">​</a></h1><p>散王剑阵符<br> S+8000<br> 消耗品<br> 这符咒来自某个符大师之手，观天下第一剑仙的龙殃剑阵所创，此符仿龙殃之决而聚天下王剑而得名。</p><p>你以一个标准动作消耗5点意志，燃烧此符激发以下效果之一，一经选定无法更改。</p><p>【万剑归引】<br> 这视为你发动一次不附带任何招式的攻击，同时引动以你为圆心的24000米范围内S级以下所有长剑或者被分类定义为――剑的物品，这些剑来自敌人的剑鞘，古墓中的宝剑，守卫的长剑等等，不论如何，你最多牵引35把长剑……随后他们如同倾斜天河之势毁灭2400米内直线性范围所有敌人，对方以反射豁免这次伤害。<br> 你牵引的长剑如果是有主之物，被他人持有或者具有任意等级的绑定特性。那么你需要以进行一次不带有副专业的攻击检定来对抗对方的意志豁免+所持剑等级（D14/C26/B38/A48/S66）的DC，只要成功那么对方长剑会被你牵引，特别的，你可以将自身操控属性（包括其附加成功）加入这次攻击检定中。<br> 同时，哪怕这次一把剑都没有牵引出来，周围古老的剑影也会为你完成这次攻击，但不附带任何效果。<br> 如果你成功牵引了长剑，那么每牵引一把长剑就能将它的武器伤害一半与所有特性加入攻击中加入这次天河之势的攻击检定里面。</p><p>【千里神行】<br> 古老的剑影被你召唤而出，只要在该位面内，你拥有目的地的坐标，那么它们就会形成一条古老的剑河带着你飞向远方，抵达你所需求的目的地，当前剑河速度为2000-8000公里一小时。<br> 特殊的：首先你得进行十分钟的准备，在这期间不可中断准备行为，在准备完成后即可以剑河速度进行游影。当处于游影状态时，人物默认失去所有动作，不可进入战斗轮（换句话说就是进入战斗则剑河速度失效）。</p><p>【龙殃破影】<br> 古老的剑影瞬间裹着你离开战场，你立刻移动不超过自身基础移速的距离，这视为一个S级命运来源的传送效果。</p><p>【长虹剑阵】<br> 由该符创造者所创剑阵，其中亦融入了龙殃剑阵的攻防兼备特点。<br> 启动该效果后，剑阵切割了时间，混沌包裹着你，令你每轮免疫一次伤害，这是一个时空来源的复活效果，持续3轮。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const S=r(p,[["render",d]]);export{f as __pageData,S as default};
